-- ============================================
-- MIGRACAO TABELA: banners
-- ============================================

CREATE TABLE IF NOT EXISTS banners (
  id SERIAL PRIMARY KEY,
  rel_estabelecimentos_id TEXT,
  titulo TEXT,
  desktop TEXT,
  mobile TEXT,
  video_link TEXT,
  link TEXT,
  status TEXT,
  created TIMESTAMP,
  last_modified TIMESTAMP
);

ON CONFLICT (id) DO NOTHING;
